// [A1] paso 2: Validate & Normalize Phone to E.164 (default Peru +51)
// Input: webhook body con campo `phone` (cualquier formato)
// Output: mismo body + `phone_e164` o `_phone_invalid: true`

const body = $input.first().json.body || $input.first().json;
const phoneRaw = (body.phone || '').toString().trim();

if (!phoneRaw) {
  return [{ json: { ...body, _phone_invalid: true, _phone_error: 'empty' } }];
}

// Strip everything except digits and leading +
let cleaned = phoneRaw.replace(/[^\d+]/g, '');

let phone_e164 = null;

if (cleaned.startsWith('+')) {
  const digits = cleaned.slice(1);
  if (digits.length < 8 || digits.length > 15) {
    return [{ json: { ...body, _phone_invalid: true, _phone_error: 'length_out_of_range' } }];
  }
  phone_e164 = '+' + digits;
} else if (cleaned.startsWith('51') && cleaned.length >= 11 && cleaned.length <= 12) {
  phone_e164 = '+' + cleaned;
} else if (cleaned.length === 9 && cleaned.startsWith('9')) {
  phone_e164 = '+51' + cleaned;
} else if (cleaned.length === 11 && cleaned.startsWith('519')) {
  phone_e164 = '+' + cleaned;
} else {
  return [{ json: { ...body, _phone_invalid: true, _phone_error: 'unknown_format' } }];
}

return [{ json: { ...body, phone_e164, _phone_invalid: false } }];

// [A1] paso 4: Compute MD5(token + accesskey) for Vtiger login
const crypto = require('crypto');

const challengeResponse = $input.first().json;
if (!challengeResponse.success) {
  throw new Error('Vtiger getchallenge failed: ' + JSON.stringify(challengeResponse));
}

const token = challengeResponse.result.token;
const accesskey = $env.VTIGER_API_ACCESSKEY;
const hash = crypto.createHash('md5').update(token + accesskey).digest('hex');

// Pasamos al siguiente nodo el hash + el lead body original (preservar a traves de la chain)
const formBody = $('Validate Phone').first().json;

return [{ json: { ...formBody, _vtiger_access_hash: hash } }];

// [A1] paso 5b: Capturar sessionName y propagar form data
const loginResponse = $input.first().json;
if (!loginResponse.success) {
  throw new Error('Vtiger login failed: ' + JSON.stringify(loginResponse));
}

const sessionName = loginResponse.result.sessionName;
const formBody = $('Validate Phone').first().json;

return [{ json: { ...formBody, _vtiger_session: sessionName } }];

// [A1] paso 7: Decidir create vs existing lead match
// Si existe: retornar lead_id y is_new=false (sin update en v1.0)
// Si no existe: forward para CREATE

const queryResponse = $input.first().json;
if (!queryResponse.success) {
  throw new Error('Vtiger query failed: ' + JSON.stringify(queryResponse));
}

const formBody = $('Validate Phone').first().json;
const session = $('Capture Session').first().json._vtiger_session;
const results = queryResponse.result || [];

if (results.length > 0) {
  // Lead existe — dedup match
  return [{ json: {
    ...formBody,
    _vtiger_session: session,
    _lead_exists: true,
    _existing_lead_id: results[0].id,
  } }];
} else {
  // Lead nuevo — CREATE flow
  return [{ json: {
    ...formBody,
    _vtiger_session: session,
    _lead_exists: false,
  } }];
}

// [A1] paso 8b: Build CREATE payload con los 12 cf_NNN + nativos
// Mapping cf_NNN segun integrations/vtiger/fields-mapping.md

const body = $input.first().json;

// Split nombre en first/last
const nombreParts = (body.nombre || '').trim().split(/\s+/);
const firstname = nombreParts[0] || '(sin nombre)';
const lastname = nombreParts.slice(1).join(' ') || '(sin apellido)';

const element = {
  // Nativos
  firstname,
  lastname,
  phone: body.phone_e164,
  email: (body.email || '').toLowerCase().trim(),
  leadstatus: 'New',
  leadsource: 'Web Site',
  description: '',

  // Custom fields (cf_NNN — ver fields-mapping.md)
  cf_853: body.utm_source || '',
  cf_855: body.utm_medium || '',
  cf_857: body.utm_campaign || '',
  cf_859: body.utm_content || '',
  cf_861: body.utm_term || '',
  cf_863: body.fbclid || '',
  cf_865: body.gclid || '',
  cf_867: body.fbc || '',
  cf_869: body.ga || '',
  cf_871: body.event_id || '',
  cf_873: body.landing_url || '',
  cf_875: body.tratamiento_interes || 'Otro / No especificado',
};

// assigned_user_id es required en Vtiger — asignar al admin (id 1)
element.assigned_user_id = '19x1';

return [{ json: {
  _vtiger_session: body._vtiger_session,
  _element_json: JSON.stringify(element),
} }];

// [A1] paso 10: Build response payload — caso CREATE exitoso

const createResponse = $input.first().json;
if (!createResponse.success) {
  throw new Error('Vtiger create failed: ' + JSON.stringify(createResponse));
}

const formBody = $('Validate Phone').first().json;

return [{ json: {
  ok: true,
  vtiger_lead_id: createResponse.result.id,
  is_new: true,
  event_id: formBody.event_id || null,
} }];

// [A1] paso 8a: Build response — caso lead ya existe (dedup match, no UPDATE en v1.0)

const body = $input.first().json;

return [{ json: {
  ok: true,
  vtiger_lead_id: body._existing_lead_id,
  is_new: false,
  event_id: body.event_id || null,
} }];
